-- Auto-generated by pg_pack (pgv, pgv_ut)
-- 2026-03-11

-- Schema: pgv
CREATE SCHEMA IF NOT EXISTS pgv;

CREATE OR REPLACE FUNCTION pgv.call_ref(p_fname text, p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_schema text;
  v_path text;
  v_qs text := '';
  v_key text;
  v_val text;
BEGIN
  -- Get current schema from route context
  v_schema := trim(LEADING '/' FROM coalesce(current_setting('pgv.route_prefix', true), ''));

  -- Verify function exists in pg_proc
  IF v_schema <> '' THEN
    IF NOT EXISTS (
      SELECT 1 FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = v_schema AND p.proname = p_fname AND p.prokind = 'f'
    ) THEN
      RAISE EXCEPTION 'pgv.call_ref: function %.% not found', v_schema, p_fname
        USING HINT = 'Check that the function exists in schema ' || v_schema;
    END IF;
  END IF;

  -- Derive path from function name: get_drawing → /drawing, get_index → /
  v_path := regexp_replace(p_fname, '^(get|post)_', '');
  IF v_path = 'index' THEN
    v_path := '/';
  ELSE
    v_path := '/' || v_path;
  END IF;

  -- Build query string from params
  FOR v_key, v_val IN SELECT k, v FROM jsonb_each_text(p_params) AS x(k, v)
  LOOP
    -- Percent-encode critical query string characters
    v_val := replace(replace(replace(replace(replace(
      v_val, '%', '%25'), '&', '%26'), '=', '%3D'), '+', '%2B'), ' ', '%20');
    IF v_qs = '' THEN
      v_qs := '?' || v_key || '=' || v_val;
    ELSE
      v_qs := v_qs || '&' || v_key || '=' || v_val;
    END IF;
  END LOOP;

  -- Build full URL with schema prefix
  IF v_schema <> '' THEN
    RETURN '/' || v_schema || v_path || v_qs;
  ELSE
    RETURN v_path || v_qs;
  END IF;
END;
$function$;
COMMENT ON FUNCTION pgv.call_ref(text,jsonb) IS 'Build a verified internal route URL from a function name + params. Checks pg_proc to detect dead links at render time.';

CREATE OR REPLACE FUNCTION pgv.card(p_title text, p_body text, p_footer text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<article>'
    || CASE WHEN p_title IS NOT NULL THEN '<header>' || p_title || '</header>' ELSE '' END
    || p_body
    || CASE WHEN p_footer IS NOT NULL THEN '<footer>' || p_footer || '</footer>' ELSE '' END
    || '</article>';
$function$;

CREATE OR REPLACE FUNCTION pgv.esc(p_text text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT replace(replace(replace(replace(replace(
    coalesce(p_text, ''),
    '&', '&amp;'), '<', '&lt;'), '>', '&gt;'), '"', '&quot;'), '''', '&#39;');
$function$;

CREATE OR REPLACE FUNCTION pgv.action(p_rpc text, p_label text, p_params jsonb DEFAULT NULL::jsonb, p_confirm text DEFAULT NULL::text, p_variant text DEFAULT 'primary'::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<button data-rpc="' || p_rpc || '"'
    || CASE WHEN p_params IS NOT NULL THEN ' data-params=''' || p_params::text || '''' ELSE '' END
    || CASE WHEN p_confirm IS NOT NULL THEN ' data-confirm="' || pgv.esc(p_confirm) || '"' ELSE '' END
    || CASE WHEN p_variant = 'danger' THEN ' class="secondary"'
            WHEN p_variant = 'outline' THEN ' class="outline"'
            ELSE '' END
    || '>' || pgv.esc(p_label) || '</button>';
$function$;

CREATE OR REPLACE FUNCTION pgv.badge(p_text text, p_variant text DEFAULT 'default'::text)
 RETURNS text
 LANGUAGE sql
