$function$;

CREATE OR REPLACE FUNCTION pgv.dl(VARIADIC p_pairs text[])
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text := '<dl class="pgv-dl">';
BEGIN
  FOR i IN 1..array_length(p_pairs, 1) BY 2 LOOP
    v_html := v_html || '<dt>' || pgv.esc(p_pairs[i]) || '</dt><dd>' || coalesce(p_pairs[i+1], '-') || '</dd>';
  END LOOP;
  RETURN v_html || '</dl>';
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.error(p_status text, p_title text, p_detail text DEFAULT NULL::text, p_hint text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text;
BEGIN
  v_html := '<article class="pgv-error">'
    || '<header><strong>' || pgv.esc(p_status) || E' \u2014 ' || pgv.esc(p_title) || '</strong></header>';
  IF p_detail IS NOT NULL THEN v_html := v_html || '<p>' || pgv.esc(p_detail) || '</p>'; END IF;
  IF p_hint IS NOT NULL THEN v_html := v_html || '<p><small>' || pgv.esc(p_hint) || '</small></p>'; END IF;
  v_html := v_html || '</article>';
  RETURN v_html;
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.filesize(p_bytes bigint)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN p_bytes IS NULL THEN '-'
    WHEN p_bytes < 1024 THEN p_bytes || ' B'
    WHEN p_bytes < 1048576 THEN round(p_bytes / 1024.0, 1) || ' KB'
    WHEN p_bytes < 1073741824 THEN round(p_bytes / 1048576.0, 1) || ' MB'
    ELSE round(p_bytes / 1073741824.0, 1) || ' GB'
  END;
$function$;

CREATE OR REPLACE FUNCTION pgv.grid(VARIADIC p_items text[])
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<div class="grid">' || array_to_string(p_items, '') || '</div>';
$function$;

CREATE OR REPLACE FUNCTION pgv.href(p_url text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT CASE
    WHEN left(p_url, 8) = 'https://' THEN p_url
    WHEN left(p_url, 7) = 'http://'  THEN p_url
    WHEN left(p_url, 2) = '//'       THEN p_url
    WHEN left(p_url, 7) = 'mailto:'  THEN p_url
    WHEN left(p_url, 4) = 'tel:'     THEN p_url
    ELSE NULL
  END;
$function$;
COMMENT ON FUNCTION pgv.href(text) IS 'External links only. Returns NULL for internal paths — use pgv.call_ref() instead.';

CREATE OR REPLACE FUNCTION pgv.input(p_name text, p_type text, p_label text, p_value text DEFAULT NULL::text, p_required boolean DEFAULT false)
