AS $function$
  SELECT to_char(p_amount, 'FM999 999 990D00') || ' EUR';
$function$;

CREATE OR REPLACE FUNCTION pgv.nav(p_brand text, p_items jsonb, p_current text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_item jsonb;
  v_href text;
  v_label text;
  v_burger boolean := coalesce((p_options->>'burger')::boolean, false);
BEGIN
  IF v_burger THEN
    v_html := '<nav class="container-fluid pgv-nav-burger" x-data="{ open: false }">';
  ELSE
    v_html := '<nav class="container-fluid">';
  END IF;

  -- Brand + burger toggle
  v_html := v_html || '<ul><li><a href="' || pgv.call_ref('get_index') || '" class="pgv-brand"><strong>' || pgv.esc(p_brand) || '</strong></a></li>';
  IF v_burger THEN
    v_html := v_html || '<li class="pgv-burger-li">'
      || '<button class="pgv-burger" @click="open = !open" aria-label="Menu">'
      || '<span x-text="open ? ''✕'' : ''☰''">☰</span></button></li>';
  END IF;
  v_html := v_html || '</ul>';

  -- Menu links
  IF v_burger THEN
    v_html := v_html || '<ul class="pgv-menu" :class="open && ''pgv-menu-open''" @click="open = false">';
  ELSE
    v_html := v_html || '<ul>';
  END IF;

  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items) LOOP
    v_href  := v_item->>'href';
    v_label := v_item->>'label';
    IF v_href = p_current THEN
      v_html := v_html || format('<li><a href="%s" aria-current="page">%s</a></li>', v_href, pgv.esc(v_label));
    ELSE
      v_html := v_html || format('<li><a href="%s">%s</a></li>', v_href, pgv.esc(v_label));
    END IF;
  END LOOP;
  v_html := v_html || '</ul>';

  -- Theme toggle
  v_html := v_html || '<ul><li>'
    || '<button class="pgv-theme-toggle" data-toggle-theme title="Changer de theme">'
    || '&#x263E;</button></li></ul></nav>';

  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION pgv.nav(text,jsonb,text,jsonb) IS 'Generate nav bar HTML. Options: burger (boolean) for responsive hamburger menu.';

CREATE OR REPLACE FUNCTION pgv.page(p_brand text, p_title text, p_path text, p_nav jsonb, p_body text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN pgv.nav(p_brand, p_nav, p_path, p_options)
    || '<main class="container">'
    || '<hgroup><h2>' || pgv.esc(p_title) || '</h2></hgroup>'
    || p_body
    || '</main>';
END;
$function$;
COMMENT ON FUNCTION pgv.page(text,text,text,jsonb,text,jsonb) IS 'Wrap body in nav + main layout. Options forwarded to pgv.nav().';

CREATE OR REPLACE FUNCTION pgv.route(p_schema text, p_path text, p_method text DEFAULT 'GET'::text, p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS "text/html"
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_nav jsonb;
  v_opts jsonb;
  v_brand text;
  v_title text;
  v_fname text;
  v_body text;
  v_detail text;
  v_hint text;
  v_route text;
  v_nargs int;
  v_argtype text;
  v_argname text;
BEGIN
  -- Get nav items
  BEGIN
    EXECUTE format('SELECT %I.nav_items()', p_schema) INTO v_nav;
  EXCEPTION WHEN undefined_function THEN
    RAISE EXCEPTION 'Module % has no nav_items() function', p_schema;
  END;

  -- Get brand (optional, fallback to schema name)
  BEGIN
    EXECUTE format('SELECT %I.brand()', p_schema) INTO v_brand;
  EXCEPTION WHEN undefined_function THEN
    v_brand := initcap(p_schema);
  END;

  -- Get nav options (optional, fallback to empty)
  BEGIN
    EXECUTE format('SELECT %I.nav_options()', p_schema) INTO v_opts;
  EXCEPTION WHEN undefined_function THEN
    v_opts := '{}'::jsonb;
  END;

  -- Derive function name: method + path
  IF p_path = '/' THEN
    v_fname := lower(p_method) || '_index';
  ELSE
    v_fname := lower(p_method) || '_' || replace(replace(trim(BOTH '/' FROM p_path), '/', '_'), '-', '_');
  END IF;

  -- Full route path
  v_route := '/' || p_schema || p_path;

  -- Set route prefix early (pgv.call_ref() needs it)
  PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);

  -- Prefix nav hrefs with schema
  v_nav := (
    SELECT jsonb_agg(
      jsonb_set(item, '{href}', to_jsonb('/' || p_schema || (item->>'href')))
    )
    FROM jsonb_array_elements(v_nav) AS item
  );

  -- Introspect function signature (max 1 arg)
  SELECT p.pronargs,
         CASE WHEN p.pronargs > 0 THEN (p.proargtypes::oid[])[0]::regtype::text END,
         CASE WHEN p.pronargs > 0 THEN p.proargnames[1] END
  INTO v_nargs, v_argtype, v_argname
  FROM pg_proc p
  JOIN pg_namespace n ON n.oid = p.pronamespace
  WHERE n.nspname = p_schema AND p.proname = v_fname AND p.prokind = 'f'
    AND p.pronargs <= 1;

  IF NOT FOUND THEN
    -- GET: return 200 with error page (shell renders HTML, no need for HTTP error)
    -- POST: return 404 so shell shows toast via _err()
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '404', true);
      RETURN '<template data-toast="error">Page non trouvee: ' || pgv.esc(p_method || ' ' || p_path) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, '404', v_route, v_nav,
      pgv.error('404', 'Page non trouvee', 'Le chemin ' || p_method || ' ' || p_path || ' n''existe pas.'), v_opts);
  END IF;

  -- Execute based on signature
  IF v_nargs = 0 THEN
    EXECUTE format('SELECT %I.%I()', p_schema, v_fname) INTO v_body;
  ELSIF v_argtype = 'jsonb' THEN
    EXECUTE format('SELECT %I.%I($1)', p_schema, v_fname) USING p_params INTO v_body;
  ELSIF v_argtype IN ('integer', 'bigint', 'text', 'uuid') THEN
    EXECUTE format('SELECT %I.%I($1::%s)', p_schema, v_fname, v_argtype)
      USING p_params->>v_argname INTO v_body;
  ELSE
    -- Composite type: deserialize jsonb into typed record
    EXECUTE format('SELECT %I.%I(jsonb_populate_record(NULL::%s, $1))', p_schema, v_fname, v_argtype)
      USING p_params INTO v_body;
  END IF;

  -- POST: return raw (toast/redirect templates, no layout)
  IF lower(p_method) = 'post' THEN
    RETURN v_body;
  END IF;

  -- GET: find title from nav
  SELECT item->>'label' INTO v_title
  FROM jsonb_array_elements(v_nav) AS item
  WHERE item->>'href' = v_route;

  IF v_title IS NULL THEN
    v_title := initcap(replace(regexp_replace(v_fname, '^(get|post)_', ''), '_', ' '));
  END IF;

  -- Wrap in page layout
  RETURN pgv.page(v_brand, v_title, v_route, v_nav, v_body, v_opts);

EXCEPTION
  WHEN raise_exception THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT, v_hint = PG_EXCEPTION_HINT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Erreur', v_detail, v_hint), v_opts);
  WHEN invalid_text_representation THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '400', true);
      RETURN '<template data-toast="error">' || pgv.esc(v_detail) || '</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('400', 'Parametre invalide', v_detail), v_opts);
  WHEN OTHERS THEN
    GET STACKED DIAGNOSTICS v_detail = MESSAGE_TEXT;
    PERFORM set_config('pgv.route_prefix', '/' || p_schema, true);
    IF lower(p_method) = 'post' THEN
      PERFORM set_config('response.status', '500', true);
      RETURN '<template data-toast="error">Erreur interne</template>';
    END IF;
    RETURN pgv.page(v_brand, 'Erreur', v_route, v_nav, pgv.error('500', 'Erreur interne', 'Une erreur inattendue est survenue.'), v_opts);
END;
$function$;
COMMENT ON FUNCTION pgv.route(text,text,text,jsonb) IS 'Router: maps method+path to get_*/post_* functions via pg_proc introspection. Supports 0-arg, scalar, jsonb, and composite type parameters.';

CREATE OR REPLACE FUNCTION pgv.diagnose(p_schema text, p_path text DEFAULT '/'::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
  v_start timestamptz;
  v_ms numeric;
  v_rows text := '';
  v_err int := 0;
  v_warn int := 0;
  v_ok int := 0;
  v_rec record;
  v_ns text;
  v_fn text;
  v_href text;
  v_clean text;
  v_params text[];
  v_inputs text[];
  v_missing text[];
BEGIN
  -- Render page
  v_start := clock_timestamp();
  BEGIN
    v_html := pgv.route(p_schema, p_path, 'GET', '{}'::jsonb);
  EXCEPTION WHEN OTHERS THEN
    RETURN pgv.error('500', p_schema || ':' || p_path, SQLERRM);
  END;
  v_ms := round(extract(epoch from clock_timestamp() - v_start) * 1000, 1);

  -- 1. Inline styles (pgv-canvas-vp uses style for height — legit, exclude)
  v_clean := regexp_replace(v_html, '<div class="pgv-canvas-vp"[^>]*>', '', 'g');
  IF v_clean ~ ' style\s*=\s*"' THEN
    v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Style | inline `style` detecte |' || chr(10);
    v_err := v_err + 1;
  ELSE
    v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Style | aucun inline style |' || chr(10);
    v_ok := v_ok + 1;
  END IF;

  -- 2. HTMX
  IF v_html ~ '\bhx-' THEN
    v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | HTMX | attributs hx-* detectes |' || chr(10);
    v_err := v_err + 1;
  ELSE
    v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | HTMX | aucun |' || chr(10);
    v_ok := v_ok + 1;
  END IF;

  -- 3. Raw <table> without <md>
  IF v_html ~ '<table[\s>]' AND v_html !~ '<md' THEN
    v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Table | `<table>` sans `<md>` |' || chr(10);
    v_warn := v_warn + 1;
  END IF;

  -- 4. data-rpc targets
  FOR v_rec IN
    SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, 'data-rpc="([^"]+)"', 'g') t(x)
  LOOP
    IF v_rec.rpc LIKE '%.%' THEN
      v_ns := split_part(v_rec.rpc, '.', 1);
      v_fn := split_part(v_rec.rpc, '.', 2);
    ELSE
      v_ns := p_schema;
      v_fn := v_rec.rpc;
    END IF;

    IF EXISTS (
      SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = v_ns AND p.proname = v_fn
    ) THEN
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | RPC | `' || v_ns || '.' || v_fn || '()` |' || chr(10);
      v_ok := v_ok + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | RPC | `' || v_ns || '.' || v_fn || '()` introuvable |' || chr(10);
      v_err := v_err + 1;
    END IF;
  END LOOP;

  -- 5. Internal href targets
  FOR v_rec IN
    SELECT DISTINCT x[1] AS raw_href FROM regexp_matches(v_html, 'href="(/[^"]*)"', 'g') t(x)
  LOOP
    v_href := v_rec.raw_href;
    -- Strip schema prefix
    IF v_href LIKE '/' || p_schema || '/%' THEN
      v_href := substr(v_href, length(p_schema) + 2);
    ELSIF v_href = '/' || p_schema OR v_href = '/' || p_schema || '/' THEN
      v_href := '/';
    END IF;
    -- Strip query string
    IF v_href LIKE '%?%' THEN v_href := split_part(v_href, '?', 1); END IF;

    v_fn := CASE WHEN v_href = '/' THEN 'get_index'
            ELSE 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_') END;

    IF EXISTS (
      SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = p_schema AND p.proname = v_fn
    ) THEN
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_fn || '()` |' || chr(10);
      v_ok := v_ok + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Lien | `' || pgv.esc(v_rec.raw_href) || '` -> `' || v_fn || '()` introuvable |' || chr(10);
      v_err := v_err + 1;
    END IF;
  END LOOP;

  -- 6. <md> blocks valid
  FOR v_rec IN
    SELECT x[1] AS md_body FROM regexp_matches(v_html, '<md[^>]*>(.*?)</md>', 'g') t(x)
  LOOP
    IF v_rec.md_body ~ '^\s*\|.+\|\s*\n\s*\|[-| ]+\|' THEN
      v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Markdown | bloc `<md>` valide |' || chr(10);
      v_ok := v_ok + 1;
    ELSE
      v_rows := v_rows || '| ' || pgv.badge('ERR', 'danger') || ' | Markdown | `<md>` sans header valide |' || chr(10);
      v_err := v_err + 1;
    END IF;
  END LOOP;

  -- 7. Form fields vs function signature
  FOR v_rec IN
    SELECT DISTINCT x[1] AS rpc FROM regexp_matches(v_html, '<form[^>]*data-rpc="([^"]+)"', 'g') t(x)
  LOOP
    SELECT proargnames INTO v_params
    FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
    WHERE n.nspname = p_schema AND p.proname = v_rec.rpc
    LIMIT 1;

    IF v_params IS NOT NULL THEN
      v_inputs := ARRAY(
        SELECT DISTINCT x[1] FROM regexp_matches(v_html, 'name="([^"]+)"', 'g') t(x)
      );
      v_missing := ARRAY(
        SELECT unnest(v_params) EXCEPT SELECT unnest(v_inputs)
      );
      IF array_length(v_missing, 1) > 0 THEN
        v_rows := v_rows || '| ' || pgv.badge('WARN', 'warning') || ' | Form | `' || v_rec.rpc || '()` params sans champ: ' || array_to_string(v_missing, ', ') || ' |' || chr(10);
        v_warn := v_warn + 1;
      ELSE
        v_rows := v_rows || '| ' || pgv.badge('OK', 'success') || ' | Form | `' || v_rec.rpc || '()` signature couverte |' || chr(10);
        v_ok := v_ok + 1;
      END IF;
    END IF;
  END LOOP;

  -- Report
  RETURN pgv.dl(
    'Page', p_schema || ' : ' || p_path,
    'Rendu', v_ms || ' ms',
    'Bilan',
      CASE WHEN v_err > 0 THEN pgv.badge(v_err || ' erreur(s)', 'danger') || ' ' ELSE '' END
      || CASE WHEN v_warn > 0 THEN pgv.badge(v_warn || ' warning(s)', 'warning') || ' ' ELSE '' END
      || pgv.badge(v_ok || ' ok', 'success'))
    || '<md>' || chr(10)
    || '| Niveau | Check | Detail |' || chr(10)
    || '|--------|-------|--------|' || chr(10)
    || v_rows
    || '</md>';
END;
$function$;
COMMENT ON FUNCTION pgv.diagnose(text,text) IS 'Diagnose a pgView page: render + check contract (styles, HTMX, RPCs, links, md, forms)';

CREATE OR REPLACE FUNCTION pgv.script(p_js text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<script>' || p_js || '</script>';
$function$;

CREATE OR REPLACE FUNCTION pgv.sel(p_name text, p_label text, p_options jsonb, p_selected text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE v_html text; v_opt jsonb; v_val text; v_lbl text;
BEGIN
  v_html := '<label>' || p_label || '<select name="' || p_name || '">';
  v_html := v_html || '<option value="">--</option>';
  FOR v_opt IN SELECT * FROM jsonb_array_elements(p_options) LOOP
    IF jsonb_typeof(v_opt) = 'string' THEN
      v_val := v_opt #>> '{}'; v_lbl := v_val;
    ELSE
      v_val := v_opt->>'value'; v_lbl := coalesce(v_opt->>'label', v_val);
    END IF;
    v_html := v_html || '<option value="' || pgv.esc(v_val) || '"'
      || CASE WHEN v_val = p_selected THEN ' selected' ELSE '' END
      || '>' || pgv.esc(v_lbl) || '</option>';
  END LOOP;
  RETURN v_html || '</select></label>';
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.stat(p_label text, p_value text, p_detail text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<article class="pgv-stat">'
    || '<small>' || pgv.esc(p_label) || '</small>'
    || '<p class="pgv-stat-value">' || p_value || '</p>'
    || CASE WHEN p_detail IS NOT NULL THEN '<small>' || pgv.esc(p_detail) || '</small>' ELSE '' END
    || '</article>';
$function$;

CREATE OR REPLACE FUNCTION pgv.svg_canvas(p_svg text, p_options jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_id text := 'sc_' || substr(md5(random()::text), 1, 8);
  v_height text := coalesce(p_options->>'height', '60vh');
  v_toolbar boolean := coalesce((p_options->>'toolbar')::boolean, true);
  v_html text;
  v_js text;
BEGIN
  IF p_svg IS NULL OR p_svg = '' THEN RETURN ''; END IF;

  v_html := '<div class="pgv-canvas" id="' || v_id || '">'
    || '<div class="pgv-canvas-vp" id="' || v_id || '_vp" style="height:' || v_height || '">'
    || p_svg
    || '</div>';

  IF v_toolbar THEN
    v_html := v_html
      || '<div class="pgv-canvas-bar">'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_out" title="Zoom out">&minus;</button>'
      || '<span class="pgv-canvas-zoom" id="' || v_id || '_zl">100%</span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_in" title="Zoom in">+</button>'
      || '<span class="pgv-canvas-sep"></span>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_fit" title="Ajuster">Fit</button>'
      || '<button class="pgv-canvas-btn" id="' || v_id || '_reset" title="1:1">1:1</button>'
      || '</div>';
  END IF;

  v_html := v_html || '</div>';

  v_js := $JS$
(function(){
  var id="__ID__",
      vp=document.getElementById(id+"_vp"),
      svg=vp&&vp.querySelector("svg"),
      zl=document.getElementById(id+"_zl");
  if(!vp||!svg||typeof panzoom==="undefined")return;
  var pz=panzoom(svg,{maxZoom:20,minZoom:0.05,smoothScroll:false,bounds:true,boundsPadding:0.2});
  function upd(){if(zl)zl.textContent=Math.round(pz.getTransform().scale*100)+"%";}
  pz.on("zoom",upd);
  pz.on("transform",upd);
  var zi=document.getElementById(id+"_in"),
      zo=document.getElementById(id+"_out"),
      fb=document.getElementById(id+"_fit"),
      rb=document.getElementById(id+"_reset");
  if(zi)zi.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,1.3);};
  if(zo)zo.onclick=function(){pz.smoothZoom(vp.clientWidth/2,vp.clientHeight/2,0.7);};
  if(rb)rb.onclick=function(){pz.moveTo(0,0);pz.zoomAbs(0,0,1);upd();};
  if(fb)fb.onclick=function(){
    var bb=svg.getBBox(),vw=vp.clientWidth,vh=vp.clientHeight,
        sc=Math.min(vw/(bb.width+bb.x*2),vh/(bb.height+bb.y*2))*0.9,
        ox=(vw-bb.width*sc)/2-bb.x*sc,
        oy=(vh-bb.height*sc)/2-bb.y*sc;
    pz.zoomAbs(0,0,sc);pz.moveTo(ox,oy);upd();
  };
  if(fb)fb.onclick();
})();
$JS$;

  v_js := replace(v_js, '__ID__', v_id);
  v_html := v_html || pgv.script(v_js);

  RETURN v_html;
END;
$function$;

CREATE OR REPLACE FUNCTION pgv.textarea(p_name text, p_label text, p_value text DEFAULT NULL::text, p_rows integer DEFAULT 3)
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT '<label>' || p_label
    || '<textarea name="' || p_name || '" rows="' || p_rows || '">'
    || coalesce(pgv.esc(p_value), '')
    || '</textarea></label>';
$function$;

GRANT USAGE ON SCHEMA pgv TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv TO web_anon;

-- Schema: pgv_ut
CREATE SCHEMA IF NOT EXISTS pgv_ut;

CREATE OR REPLACE FUNCTION pgv_ut.assert_page(p_html text, p_schema text DEFAULT NULL::text)
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_rpc text;
  v_schema text;
  v_fname text;
  v_href text;
  v_page_fn text;
  v_match text[];
  v_errors int := 0;
BEGIN
  -- 1. No inline styles
  IF p_html ~ 'style\s*=\s*"' THEN
    v_errors := v_errors + 1;
    RETURN NEXT ok(false, 'no inline styles (style="...")');
  ELSE
    RETURN NEXT ok(true, 'no inline styles');
  END IF;

  -- 2. All data-rpc point to existing functions
  FOR v_match IN
    SELECT regexp_matches(p_html, 'data-rpc="([^"]+)"', 'g')
  LOOP
    v_rpc := v_match[1];
    -- data-rpc may be "schema.fn" or just "fn" (resolved via p_schema)
    IF v_rpc LIKE '%.%' THEN
      v_schema := split_part(v_rpc, '.', 1);
      v_fname := split_part(v_rpc, '.', 2);
    ELSIF p_schema IS NOT NULL THEN
      v_schema := p_schema;
      v_fname := v_rpc;
    ELSE
      -- Cannot resolve without schema context — skip
      RETURN NEXT ok(true, format('data-rpc "%s" (schema unknown, skipped)', v_rpc));
      CONTINUE;
    END IF;

    IF EXISTS (
      SELECT 1 FROM pg_proc p
      JOIN pg_namespace n ON n.oid = p.pronamespace
      WHERE n.nspname = v_schema AND p.proname = v_fname
    ) THEN
      RETURN NEXT ok(true, format('data-rpc "%s" -> %s.%s() exists', v_rpc, v_schema, v_fname));
    ELSE
      v_errors := v_errors + 1;
      RETURN NEXT ok(false, format('data-rpc "%s" -> %s.%s() NOT FOUND', v_rpc, v_schema, v_fname));
    END IF;
  END LOOP;

  -- 3. All href="/path" resolve to get_* functions (if schema known)
  IF p_schema IS NOT NULL THEN
    FOR v_match IN
      SELECT regexp_matches(p_html, 'href="(/[^"]*)"', 'g')
    LOOP
      v_href := v_match[1];
      -- Skip anchors and external
      IF v_href LIKE '#%' OR v_href LIKE 'http%' THEN
        CONTINUE;
      END IF;

      -- Strip schema prefix if present (e.g. /cad/drawing?id=1 → /drawing?id=1)
      IF v_href LIKE '/' || p_schema || '/%' THEN
        v_href := substr(v_href, length(p_schema) + 2);
      ELSIF v_href = '/' || p_schema || '/' OR v_href = '/' || p_schema THEN
        v_href := '/';
      END IF;

      -- Strip query string (e.g. /drawing?id=42 → /drawing)
      IF v_href LIKE '%?%' THEN
        v_href := split_part(v_href, '?', 1);
      END IF;

      -- Derive expected function: /foo → get_foo, / → get_index
      IF v_href = '/' THEN
        v_page_fn := 'get_index';
      ELSE
        v_page_fn := 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_');
      END IF;

      IF EXISTS (
        SELECT 1 FROM pg_proc p
        JOIN pg_namespace n ON n.oid = p.pronamespace
        WHERE n.nspname = p_schema AND p.proname = v_page_fn
      ) THEN
        RETURN NEXT ok(true, format('href "%s" -> %s.%s() exists', v_match[1], p_schema, v_page_fn));
      ELSE
        v_errors := v_errors + 1;
        RETURN NEXT ok(false, format('href "%s" -> %s.%s() NOT FOUND', v_match[1], p_schema, v_page_fn));
      END IF;
    END LOOP;
  END IF;

  -- 4. <md> blocks contain valid markdown table headers
  FOR v_match IN
    SELECT regexp_matches(p_html, '<md[^>]*>([\s\S]*?)</md>', 'g')
  LOOP
    IF v_match[1] ~ '^\s*\|.+\|\s*\n\s*\|[-| ]+\|' THEN
      RETURN NEXT ok(true, 'md block has valid table header');
    ELSE
      v_errors := v_errors + 1;
      RETURN NEXT ok(false, 'md block missing table header (| col | ... | + separator)');
    END IF;
  END LOOP;

  -- 5. Summary
  IF v_errors = 0 THEN
    RETURN NEXT ok(true, format('page contract valid (%s checks passed)', v_errors));
  END IF;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.assert_page(text,text) IS 'Validate pgView HTML contract: data-rpc targets exist, href routes resolve to get_* functions, no inline styles, md blocks valid.';

CREATE OR REPLACE FUNCTION pgv_ut.test_action_data_contract()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE v text;
BEGIN
  v := pgv.action('do_thing', 'Click', '{"id":1}'::jsonb, 'Sure?');
  RETURN NEXT ok(v LIKE '%data-rpc="do_thing"%', 'action has data-rpc');
  RETURN NEXT ok(v LIKE '%data-params%',         'action has data-params');
  RETURN NEXT ok(v LIKE '%data-confirm="Sure?"%', 'action has data-confirm');
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_badge_css_classes()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(
    pgv.badge('test') LIKE '%class="pgv-badge%',
    'badge(default) outputs class pgv-badge'
  );
  RETURN NEXT ok(
    pgv.badge('test') NOT LIKE '%style=%',
    'badge(default) has no inline style'
  );
  RETURN NEXT ok(
    pgv.badge('ok', 'success') LIKE '%pgv-badge-success%',
    'badge(success) outputs pgv-badge-success'
  );
  RETURN NEXT ok(
    pgv.badge('ko', 'danger') LIKE '%pgv-badge-danger%',
    'badge(danger) outputs pgv-badge-danger'
  );
  RETURN NEXT ok(
    pgv.badge('w', 'warning') LIKE '%pgv-badge-warning%',
    'badge(warning) outputs pgv-badge-warning'
  );
  RETURN NEXT ok(
    pgv.badge('i', 'info') LIKE '%pgv-badge-info%',
    'badge(info) outputs pgv-badge-info'
  );
  RETURN NEXT ok(
    pgv.badge('p', 'primary') LIKE '%pgv-badge-primary%',
    'badge(primary) outputs pgv-badge-primary'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_call_ref()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- Without route prefix (app mode): no validation, simple path
  PERFORM set_config('pgv.route_prefix', '', true);

  RETURN NEXT is(pgv.call_ref('get_index'), '/',
    'get_index without prefix → /');

  RETURN NEXT is(pgv.call_ref('get_drawings'), '/drawings',
    'get_drawings without prefix → /drawings');

  RETURN NEXT is(pgv.call_ref('get_drawing', '{"id": "42"}'::jsonb), '/drawing?id=42',
    'get_drawing with param → /drawing?id=42');

  RETURN NEXT is(pgv.call_ref('post_save', '{"id": "1", "name": "test"}'::jsonb), '/save?id=1&name=test',
    'post_save with multiple params → query string');

  -- With route prefix (dev mode): validates against pg_proc
  PERFORM set_config('pgv.route_prefix', '/pgv_qa', true);

  RETURN NEXT is(pgv.call_ref('get_index'), '/pgv_qa/',
    'get_index with prefix → /pgv_qa/');

  RETURN NEXT is(pgv.call_ref('get_atoms'), '/pgv_qa/atoms',
    'get_atoms (exists in pgv_qa) → /pgv_qa/atoms');

  -- Dead link detection
  RETURN NEXT throws_ok(
    $$SELECT pgv.call_ref('get_does_not_exist')$$,
    'P0001',
    'pgv.call_ref: function pgv_qa.get_does_not_exist not found',
    'dead link raises exception'
  );
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_call_ref() IS 'Tests for pgv.call_ref: path generation, prefix handling, dead link detection';

CREATE OR REPLACE FUNCTION pgv_ut.test_dl_css_class()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(
    pgv.dl('k', 'v') LIKE '%class="pgv-dl"%',
    'dl outputs class pgv-dl'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_error_css_classes()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(
    pgv.error('404', 'Not found') LIKE '%class="pgv-error"%',
    'error outputs class pgv-error'
  );
  RETURN NEXT ok(
    pgv.error('404', 'Not found') NOT LIKE '%style=%',
    'error has no inline style'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_href_with_prefix()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  -- External URLs pass through
  RETURN NEXT is(pgv.href('https://example.com'), 'https://example.com', 'href passes https');
  RETURN NEXT is(pgv.href('http://localhost:3000'), 'http://localhost:3000', 'href passes http');
  RETURN NEXT is(pgv.href('//cdn.example.com/lib.js'), '//cdn.example.com/lib.js', 'href passes protocol-relative');
  RETURN NEXT is(pgv.href('mailto:test@example.com'), 'mailto:test@example.com', 'href passes mailto');
  RETURN NEXT is(pgv.href('tel:+33123456789'), 'tel:+33123456789', 'href passes tel');

  -- Internal paths return NULL (use call_ref instead)
  RETURN NEXT is(pgv.href('/atoms'), NULL, 'href rejects internal path /atoms');
  RETURN NEXT is(pgv.href('/'), NULL, 'href rejects internal path /');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_href_with_prefix() IS 'Test pgv.href: external URLs pass through, internal paths return NULL';

CREATE OR REPLACE FUNCTION pgv_ut.test_nav_theme_toggle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE v text;
BEGIN
  v := pgv.nav('B', '[{"href":"/","label":"H"}]'::jsonb, '/');
  RETURN NEXT ok(v LIKE '%data-toggle-theme%', 'nav has theme toggle');
  RETURN NEXT ok(v LIKE '%pgv-theme-toggle%', 'theme toggle has CSS class');
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_no_htmx()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE v text;
BEGIN
  v := pgv.badge('x') || pgv.stat('l','v') || pgv.card('t','b')
    || pgv.action('fn', 'btn', NULL::jsonb) || pgv.error('400','err')
    || pgv.nav('B', '[{"href":"/","label":"H"}]'::jsonb, '/');
  RETURN NEXT ok(
    v NOT LIKE '%hx-get%' AND v NOT LIKE '%hx-post%'
    AND v NOT LIKE '%hx-target%' AND v NOT LIKE '%hx-swap%'
    AND v NOT LIKE '%hx-vals%' AND v NOT LIKE '%hx-trigger%',
    'zero hx-* attributes in pgv output'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_page_no_inline_style()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(
    pgv.page('Test', 'T', '/', '[]'::jsonb, '<p>x</p>') NOT LIKE '%style=%',
    'page has no inline style'
  );
END;
$function$;

CREATE OR REPLACE FUNCTION pgv_ut.test_route_all_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_item jsonb;
  v_href text;
  v_html text;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    v_html := pgv.route('pgv_qa', v_href, 'GET');
    RETURN NEXT ok(v_html IS NOT NULL AND length(v_html) > 0,
      format('route pgv_qa %s renders HTML', v_href));
    RETURN NEXT ok(v_html LIKE '%<nav%',
      format('route pgv_qa %s has nav', v_href));
    RETURN NEXT ok(v_html LIKE '%<main%',
      format('route pgv_qa %s has main', v_href));
  END LOOP;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_all_pages_render() IS 'Test every nav page renders without error via pgv.route';

CREATE OR REPLACE FUNCTION pgv_ut.test_route_nav_pages_exist()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_schema text := 'pgv_qa';
  v_item jsonb;
  v_href text;
  v_fname text;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    IF v_href = '/' THEN
      v_fname := 'get_index';
    ELSE
      v_fname := 'get_' || replace(replace(trim(BOTH '/' FROM v_href), '/', '_'), '-', '_');
    END IF;
    RETURN NEXT ok(
      EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
             WHERE n.nspname = v_schema AND p.proname = v_fname),
      format('nav %s -> %s.%s() exists', v_href, v_schema, v_fname)
    );
  END LOOP;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_nav_pages_exist() IS 'Test every nav item points to an existing page function';

CREATE OR REPLACE FUNCTION pgv_ut.test_route_prefixes_nav()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- pgv_qa has nav_items with href="/atoms" etc.
  v_html := pgv.route('pgv_qa', '/', 'GET');

  -- Nav links should be prefixed with /pgv_qa
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/"%', 'nav dashboard href prefixed');
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/atoms"%', 'nav atoms href prefixed');
  RETURN NEXT ok(v_html LIKE '%href="/pgv_qa/forms"%', 'nav forms href prefixed');

  -- route_prefix should be set for page functions
  RETURN NEXT is(current_setting('pgv.route_prefix', true), '/pgv_qa', 'route_prefix set after route call');
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_prefixes_nav() IS 'Test pgv.route prefixes nav hrefs and sets route_prefix';

CREATE OR REPLACE FUNCTION pgv_ut.test_route_rpc_targets_exist()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_schema text := 'pgv_qa';
  v_item jsonb;
  v_href text;
  v_html text;
  v_rpc text;
BEGIN
  FOR v_item IN SELECT * FROM jsonb_array_elements(pgv_qa.nav_items()) LOOP
    v_href := v_item->>'href';
    v_html := pgv.route(v_schema, v_href, 'GET');
    -- Extract all data-rpc="xxx" values
    FOR v_rpc IN
      SELECT (regexp_matches(v_html, 'data-rpc="([^"]+)"', 'g'))[1]
    LOOP
      RETURN NEXT ok(
        EXISTS(SELECT 1 FROM pg_proc p JOIN pg_namespace n ON n.oid = p.pronamespace
               WHERE n.nspname = v_schema AND p.proname = v_rpc),
        format('data-rpc="%s" on %s -> %s.%s() exists', v_rpc, v_href, v_schema, v_rpc)
      );
    END LOOP;
  END LOOP;
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_rpc_targets_exist() IS 'Test every data-rpc target in rendered pages exists as a function in the schema';

CREATE OR REPLACE FUNCTION pgv_ut.test_route_typed_dispatch()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text;
BEGIN
  -- Test GET with scalar param: get_test_param(p_id int) should be callable
  -- First create a temporary test function
  EXECUTE $x$
    CREATE OR REPLACE FUNCTION pgv_qa.get_test_param(p_id integer)
    RETURNS text LANGUAGE sql AS $f$
      SELECT '<p>ID=' || $1::text || '</p>';
    $f$
  $x$;

  v_html := pgv.route('pgv_qa', '/test-param', 'GET', '{"p_id": "42"}'::jsonb);
  RETURN NEXT ok(v_html LIKE '%ID=42%', 'route dispatches get_ with scalar int param');
  RETURN NEXT ok(v_html LIKE '%<nav%', 'scalar param page has layout');

  -- Test GET with 0 args still works
  v_html := pgv.route('pgv_qa', '/atoms', 'GET');
  RETURN NEXT ok(v_html LIKE '%pgv-badge%', 'route dispatches get_ with 0 args');

  -- Test POST returns raw (no layout)
  EXECUTE $x$
    CREATE OR REPLACE FUNCTION pgv_qa.post_test_action()
    RETURNS text LANGUAGE sql AS $f$
      SELECT '<template data-toast="success">Done</template>';
    $f$
  $x$;

  v_html := pgv.route('pgv_qa', '/test-action', 'POST');
  RETURN NEXT ok(v_html LIKE '%data-toast%', 'POST returns toast template');
  RETURN NEXT ok(v_html NOT LIKE '%<nav%', 'POST has no layout wrapping');

  -- Cleanup
  DROP FUNCTION pgv_qa.get_test_param(integer);
  DROP FUNCTION pgv_qa.post_test_action();
END;
$function$;
COMMENT ON FUNCTION pgv_ut.test_route_typed_dispatch() IS 'Test router dispatches get_ with scalar param and post_ with composite type';

CREATE OR REPLACE FUNCTION pgv_ut.test_stat_css_classes()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN NEXT ok(
    pgv.stat('L', '42') LIKE '%class="pgv-stat"%',
    'stat outputs class pgv-stat'
  );
  RETURN NEXT ok(
    pgv.stat('L', '42') LIKE '%class="pgv-stat-value"%',
    'stat outputs class pgv-stat-value'
  );
  RETURN NEXT ok(
    pgv.stat('L', '42') NOT LIKE '%style=%',
    'stat has no inline style'
  );
END;
$function$;

GRANT USAGE ON SCHEMA pgv_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA pgv_ut TO web_anon;
